# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka import KafkaAdminClient, NewTopic, AdminCreateTopicsError

def create_topics(admin_client, topic_list):
    try:
        admin_client.create_topics(topics=topic_list)
        print("Created topics successfully.")
    except AdminCreateTopicsError as e:
        for err in e.errs():
            print(f"Failed to create topic {err.topic}: {err}")

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("topics", metavar="T", type=str, nargs="+", help="Kafka topics to create (e.g., my-topic1, my-topic2)")
    parser.add_argument("--replication_factor", type=int, default=1, help="Replication factor for the created topics")
    parser.add_argument("--partitions", type=int, default=1, help="Number of partitions for the created topics")
    args = parser.parse_args()

    config = {
        'bootstrap.servers': 'localhost:9092',  # Replace with your Kafka bootstrap server
        'request.timeout.ms': 30000,
        'enable.auto.commit': False
    }

    admin_client = KafkaAdminClient(config=config)
    topic_list = []

    for topic in args.topics:
        topic_list.append(NewTopic(topic, partitions=args.partitions, replication_factor=args.replication_factor))

    create_topics(admin_client, topic_list)
    admin_client.close()

if __name__ == "__main__":
    main()